const got = $input.first().json.headers?.['x-gaiada-bridge-secret'];
if (!got || got !== $env.N8N_BRIDGE_SECRET) throw new Error('bad bridge secret');
const e = $input.first().json.body ?? {};
if (e.v !== 1) throw new Error(`unexpected envelope version ${e.v}`);
return [{ json: { tenantId: e.tenantId, clientId: e.entityId, clientName: e.payload?.name ?? 'New client' } }];

// Carry tenantId forward and pull the new projectId out of the SSE-framed reply.
const prev = $('Verify secret + extract').first().json;
const raw = $input.first().json.data ?? $input.first().json.body ?? '';
const line = String(raw).split('\n').find((l) => l.startsWith('data:')) ?? '';
const rpc = JSON.parse(line.slice(5).trim());
if (rpc.result?.isError) throw new Error(rpc.result.content?.[0]?.text ?? 'projects.create failed (a medium+ write would be suspended here)');
const project = JSON.parse(rpc.result?.content?.[0]?.text ?? '{}');
return [{ json: { tenantId: prev.tenantId, projectId: project.id } }];
